        $lines += "Artifacts to Delete:"
        foreach ($a in ($Plan.ToDelete | Sort-Object CreatedAt)) {
            $lines += "  - $($a.Name)  [$($a.SizeMB) MB, created $($a.CreatedAt.ToString('yyyy-MM-dd')), run $($a.WorkflowRunId)]"
        }
    }

    return $lines -join "`n"
}

